describe('victory conditions C++ parity', () => {
  it('any non-excluded entity prevents defeat (C++ hasAnyObjects parity)', () => {
    // Source parity: C++ hasAnyObjects() counts ALL non-excluded entities regardless of
    // MP_COUNT_FOR_VICTORY. A structure without MP_COUNT_FOR_VICTORY still prevents defeat.
    const bundle = makeBundle({
      objects: [
        makeObjectDef('USAMine', 'America', ['STRUCTURE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
        makeObjectDef('GLATank', 'GLA', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 500, InitialHealth: 500 }),
          makeBlock('Locomotor', 'BasicLocomotor LocoTag', { Speed: 10 }),
          makeBlock('Behavior', 'AIUpdateInterface ModuleTag_AI', {}),
        ]),
      ],
    });

    const scene = new THREE.Scene();
    const logic = new GameLogicSubsystem(scene);
    logic.loadMapObjects(
      makeMap([
        // America has only a STRUCTURE without MP_COUNT_FOR_VICTORY — NOT defeated per C++.
        makeMapObject('USAMine', 50, 50),
        makeMapObject('GLATank', 100, 100),
      ]),
      makeRegistry(bundle),
      makeHeightmap(),
    );
    logic.setTeamRelationship('America', 'GLA', 0);
    logic.setTeamRelationship('GLA', 'America', 0);
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'GLA');
    logic.setSidePlayerType('America', 'HUMAN');
    logic.setSidePlayerType('GLA', 'HUMAN');

    // Run frames — America has a STRUCTURE (no MP_COUNT_FOR_VICTORY). C++ hasAnyObjects
    // counts all non-excluded entities, so America should NOT be defeated.
    for (let i = 0; i < 5; i++) logic.update(1 / 30);

    const gameEnd = logic.getGameEndState();
    // Game should NOT end — both sides still have entities.
    expect(gameEnd).toBeNull();
  });

  it('detects alliance-based victory (allied sides survive together)', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('USATank', 'America', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 200, InitialHealth: 200 }),
          makeBlock('Locomotor', 'BasicLocomotor LocoTag', { Speed: 10 }),
          makeBlock('Behavior', 'AIUpdateInterface ModuleTag_AI', {}),
        ]),
        makeObjectDef('ChinaTank', 'China', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 200, InitialHealth: 200 }),
          makeBlock('Locomotor', 'BasicLocomotor LocoTag', { Speed: 10 }),
          makeBlock('Behavior', 'AIUpdateInterface ModuleTag_AI', {}),
        ]),
      ],
    });

    const scene = new THREE.Scene();
    const logic = new GameLogicSubsystem(scene);
    logic.loadMapObjects(
      makeMap([
        makeMapObject('USATank', 30, 30),
        makeMapObject('ChinaTank', 70, 70),
      ]),
      makeRegistry(bundle),
      makeHeightmap(),
    );
    // America and China are mutual allies.
    logic.setTeamRelationship('America', 'China', 2);
    logic.setTeamRelationship('China', 'America', 2);
    // GLA is an enemy but has no entities — already defeated.
    logic.setTeamRelationship('America', 'GLA', 0);
    logic.setTeamRelationship('GLA', 'America', 0);
    logic.setTeamRelationship('China', 'GLA', 0);
    logic.setTeamRelationship('GLA', 'China', 0);
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'China');
    logic.setPlayerSide(2, 'GLA');
    logic.setSidePlayerType('America', 'HUMAN');
    logic.setSidePlayerType('China', 'HUMAN');
    logic.setSidePlayerType('GLA', 'HUMAN');

    for (let i = 0; i < 5; i++) logic.update(1 / 30);

    const gameEnd = logic.getGameEndState();
    expect(gameEnd).not.toBeNull();
    // GLA is defeated, and America+China are allied — game should end with both as victors.
    expect(gameEnd!.defeatedSides).toContain('gla');
    expect(gameEnd!.victorSides).toContain('america');
    expect(gameEnd!.victorSides).toContain('china');
  });

  it('kills remaining entities on defeat and reveals map', () => {
    // Source parity: Player::killPlayer — all entities destroyed on defeat.
    // Set up a side with ONE entity. GLA side has a tank that kills it.
    // After defeat, killRemainingEntitiesForSide destroys stragglers.
    const bundle = makeBundle({
      objects: [
        makeObjectDef('USAPowerPlant', 'America', ['STRUCTURE', 'MP_COUNT_FOR_VICTORY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
        makeObjectDef('GLATank', 'GLA', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 500, InitialHealth: 500 }),
          makeBlock('Locomotor', 'BasicLocomotor LocoTag', { Speed: 10 }),
          makeBlock('Behavior', 'AIUpdateInterface ModuleTag_AI', {}),
          makeBlock('WeaponSet', 'WeaponSet', { Weapon: ['PRIMARY', 'TestGun'] }),
        ]),
      ],
      weapons: [
        makeWeaponDef('TestGun', {
          PrimaryDamage: 500, PrimaryDamageRadius: 0,
          DamageType: 'ARMOR_PIERCING', AttackRange: 200,
          DelayBetweenShots: 100, ClipSize: 1, AutoReloadsClip: 'Yes',
        }),
      ],
    });

    const scene = new THREE.Scene();
    const logic = new GameLogicSubsystem(scene);
    logic.loadMapObjects(
      makeMap([
        makeMapObject('USAPowerPlant', 50, 50),
        makeMapObject('GLATank', 55, 55),
      ]),
      makeRegistry(bundle),
      makeHeightmap(),
    );
    logic.setTeamRelationship('America', 'GLA', 0);
    logic.setTeamRelationship('GLA', 'America', 0);
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'GLA');
    logic.setSidePlayerType('America', 'HUMAN');
    logic.setSidePlayerType('GLA', 'HUMAN');

    // Attack the power plant to destroy it.
    logic.submitCommand({ type: 'attackEntity', entityId: 2, targetEntityId: 1 });

    // Run enough frames for the tank to fire and destroy the power plant.
    for (let i = 0; i < 120; i++) logic.update(1 / 30);

    // Power plant destroyed → USA has zero non-excluded entities → defeated.
    const gameEnd = logic.getGameEndState();
    expect(gameEnd).not.toBeNull();
    expect(gameEnd!.defeatedSides).toContain('america');
    expect(gameEnd!.victorSides).toContain('gla');

    // The power plant should be destroyed (health 0 or null entity state).
    const plant = logic.getEntityState(1);
    expect(plant === null || plant.health <= 0).toBe(true);
  });
});

describe('skirmish starting entities', () => {
  it('spawns command center and dozer at Player_N_Start waypoints', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('AmericaCommandCenter', 'America', ['STRUCTURE', 'COMMANDCENTER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 5000, InitialHealth: 5000 }),
        ]),
        makeObjectDef('AmericaVehicleDozer', 'America', ['VEHICLE', 'DOZER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 200, InitialHealth: 200 }),
        ]),
        makeObjectDef('ChinaCommandCenter', 'China', ['STRUCTURE', 'COMMANDCENTER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 5000, InitialHealth: 5000 }),
        ]),
        makeObjectDef('ChinaVehicleDozer', 'China', ['VEHICLE', 'DOZER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 200, InitialHealth: 200 }),
        ]),
      ],
      factions: [
        {
          name: 'FactionAmerica',
          side: 'America',
          fields: {
            Side: 'America',
            StartingBuilding: 'AmericaCommandCenter',
            StartingUnit0: 'AmericaVehicleDozer',
          },
        } as FactionDef,
        {
          name: 'FactionChina',
          side: 'China',
          fields: {
            Side: 'China',
            StartingBuilding: 'ChinaCommandCenter',
            StartingUnit0: 'ChinaVehicleDozer',
          },
        } as FactionDef,
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    const mapData = makeMap([], 128, 128);
    // Add Player_1_Start and Player_2_Start waypoints.
    mapData.waypoints = {
      nodes: [
        { id: 1, name: 'Player_1_Start', position: { x: 50, y: 50, z: 0 } },
        { id: 2, name: 'Player_2_Start', position: { x: 100, y: 100, z: 0 } },
      ],
      links: [],
    };
    logic.loadMapObjects(mapData, makeRegistry(bundle), makeHeightmap(128, 128));
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'China');

    logic.spawnSkirmishStartingEntities();

    const entities = logic.getRenderableEntityStates();
    const americaEntities = entities.filter(e => e.side === 'America' || e.side === 'america');
    const chinaEntities = entities.filter(e => e.side === 'China' || e.side === 'china');

    // Should have spawned 2 entities per side (command center + dozer).
    expect(americaEntities.length).toBe(2);
    expect(chinaEntities.length).toBe(2);
  });

  it('filters road and waypoint template names from entity spawning', () => {
    // Source parity: C++ TerrainRoads handles road objects and
    // WaypointManager handles waypoints — neither goes through
    // ThingFactory / GameLogic entity spawning.
    const bundle = makeBundle({
      objects: [
        makeObjectDef('Tree01', '', ['SHRUBBERY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 50, InitialHealth: 50 }),
        ]),
      ],
    });
    const logic = new GameLogicSubsystem(new THREE.Scene());
    const mapData = makeMap([
      makeMapObject('Tree01', 10, 10),           // real entity
      makeMapObject('DirtRoad4', 20, 20),         // road → should be skipped
      makeMapObject('Sidewalk', 30, 30),          // road → should be skipped
      makeMapObject('*Waypoints/Waypoint', 40, 40), // waypoint → should be skipped
      makeMapObject('GravelRoad', 50, 50),        // road → should be skipped
    ]);
    logic.loadMapObjects(mapData, makeRegistry(bundle), makeHeightmap(64, 64));

    const entities = logic.getRenderableEntityStates();
    // Only the Tree01 should be spawned — roads and waypoints are filtered.
    expect(entities.length).toBe(1);
    expect(entities[0]!.templateName).toBe('Tree01');
  });

  it('does not trigger immediate defeat when starting entities exist', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('AmericaCommandCenter', 'America', ['STRUCTURE', 'COMMANDCENTER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 5000, InitialHealth: 5000 }),
        ]),
        makeObjectDef('AmericaVehicleDozer', 'America', ['VEHICLE', 'DOZER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 200, InitialHealth: 200 }),
        ]),
        makeObjectDef('ChinaCommandCenter', 'China', ['STRUCTURE', 'COMMANDCENTER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 5000, InitialHealth: 5000 }),
        ]),
        makeObjectDef('ChinaVehicleDozer', 'China', ['VEHICLE', 'DOZER'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 200, InitialHealth: 200 }),
        ]),
      ],
      factions: [
        {
          name: 'FactionAmerica',
          side: 'America',
          fields: {
            Side: 'America',
            StartingBuilding: 'AmericaCommandCenter',
            StartingUnit0: 'AmericaVehicleDozer',
          },
        } as FactionDef,
        {
          name: 'FactionChina',
          side: 'China',
          fields: {
            Side: 'China',
            StartingBuilding: 'ChinaCommandCenter',
            StartingUnit0: 'ChinaVehicleDozer',
          },
        } as FactionDef,
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    const mapData = makeMap([], 128, 128);
    mapData.waypoints = {
      nodes: [
        { id: 1, name: 'Player_1_Start', position: { x: 50, y: 50, z: 0 } },
        { id: 2, name: 'Player_2_Start', position: { x: 100, y: 100, z: 0 } },
      ],
      links: [],
    };
    logic.loadMapObjects(mapData, makeRegistry(bundle), makeHeightmap(128, 128));
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'China');
    logic.spawnSkirmishStartingEntities();

    // Run several frames — should NOT trigger defeat.
    for (let i = 0; i < 10; i++) {
      logic.update(1 / 30);
    }

    const endState = logic.getGameEndState();
    expect(endState).toBeNull();
  });

  it('getWaypointPosition returns position for Player_N_Start waypoints', () => {
    // Source parity: TheTerrainLogic->getWaypointByName resolves named
    // waypoints embedded in the map data.  The browser port replicates
    // this via resolveScriptWaypointPosition (private) exposed through
    // the public getWaypointPosition API.
    const logic = new GameLogicSubsystem(new THREE.Scene());
    const mapData = makeMap([], 128, 128);
    mapData.waypoints = {
      nodes: [
        { id: 1, name: 'Player_1_Start', position: { x: 200, y: 300, z: 0 } },
        { id: 2, name: 'Player_2_Start', position: { x: 800, y: 700, z: 0 } },
      ],
      links: [],
    };
    logic.loadMapObjects(mapData, makeRegistry(makeBundle({ objects: [] })), makeHeightmap(128, 128));

    const p1 = logic.getWaypointPosition('Player_1_Start');
    expect(p1).toEqual({ x: 200, z: 300 });

    const p2 = logic.getWaypointPosition('Player_2_Start');
    expect(p2).toEqual({ x: 800, z: 700 });

    const missing = logic.getWaypointPosition('NonExistentWaypoint');
    expect(missing).toBeNull();
  });

  it('skips simultaneous all-side defeat on empty skirmish maps', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('TankA', 'America', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
        makeObjectDef('TankC', 'China', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    // Empty map — no objects. This simulates a skirmish map before starting entities spawn.
    logic.loadMapObjects(makeMap([], 128, 128), makeRegistry(bundle), makeHeightmap(128, 128));
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'China');

    // Run first frame — both sides have zero entities, frame <= 1.
    logic.update(1 / 30);

    // Game should NOT end as a draw — the early-frame guard should prevent it.
    const endState = logic.getGameEndState();
    expect(endState).toBeNull();
  });

  it('triggers simultaneous defeat after the startup grace period', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('TankA', 'America', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
        makeObjectDef('TankC', 'China', ['VEHICLE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    const map = makeMap([], 128, 128);
    logic.loadMapObjects(map, makeRegistry(bundle), makeHeightmap(128, 128));
    logic.setPlayerSide(0, 'America');
    logic.setPlayerSide(1, 'China');

    // Advance past the grace period (frame > 2) with no entities.
    // Guard is <= 2 because main.ts calls gameLogic.update(0) pre-init for fog-of-war.
    logic.update(1 / 30); // frame 1 — grace still active
    logic.update(1 / 30); // frame 2 — grace still active
    logic.update(1 / 30); // frame 3 — grace expired, both sides have 0 entities

    // Both sides defeated after grace period — game SHOULD end.
    const endState = logic.getGameEndState();
    expect(endState).not.toBeNull();
  });
});

