    expect(logic.evaluateScriptMusicHasCompleted({ musicName: 'TrackA', index: 2 })).toBe(false);

    logic.notifyScriptVideoCompleted('IntroMovie');
    logic.notifyScriptSpeechCompleted('SpeechLineA');
