  it('executes visual-speed and hulk-lifetime override actions using source action ids', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('TimedHulkUnit', 'Neutral', ['VEHICLE', 'HULK'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
          makeBlock('Behavior', 'LifetimeUpdate ModuleTag_Lifetime', {
            MinLifetime: 5000, // 150 frames
            MaxLifetime: 5000,
          }),
          makeBlock('Behavior', 'SlowDeathBehavior ModuleTag_SlowDeath', {
            SinkDelay: 300, // 9 frames
            SinkDelayVariance: 0,
            DestructionDelay: 600, // 18 frames
            DestructionDelayVariance: 0,
            SinkRate: 0.5,
            ProbabilityModifier: 10,
          }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      makeMap([], 64, 64),
      makeRegistry(bundle),
      makeHeightmap(64, 64),
    );

    const privateApi = logic as unknown as {
      applyWeaponDamageAmount: (
        sourceEntityId: number | null,
        target: unknown,
        amount: number,
        damageType: string,
      ) => void;
      spawnedEntities: Map<number, {
        lifetimeDieFrame: number | null;
        slowDeathState: {
          sinkFrame: number;
          midpointFrame: number;
          destructionFrame: number;
        } | null;
      }>;
    };

    expect(logic.getScriptVisualSpeedMultiplier()).toBe(1);
    expect(logic.executeScriptAction({
      actionType: 22, // SET_VISUAL_SPEED_MULTIPLIER
      params: [3],
    })).toBe(true);
    expect(logic.getScriptVisualSpeedMultiplier()).toBe(3);

    expect(logic.getScriptHulkLifetimeOverrideFrames()).toBe(-1);
    expect(logic.executeScriptAction({
      actionType: 507, // SCRIPTING_OVERRIDE_HULK_LIFETIME
      params: [2.5], // 75 frames
    })).toBe(true);
    expect(logic.getScriptHulkLifetimeOverrideFrames()).toBe(75);

    expect(logic.executeScriptAction({
      actionType: 23, // CREATE_OBJECT
      params: ['TimedHulkUnit', 'HulkTeam', { x: 20, y: 0, z: 20 }, 0],
    })).toBe(true);
    const overrideHulk = privateApi.spawnedEntities.get(1);
    expect(overrideHulk).toBeDefined();
    expect(overrideHulk!.lifetimeDieFrame).toBe(75);

    privateApi.applyWeaponDamageAmount(null, overrideHulk, 999, 'UNRESISTABLE');
    expect(overrideHulk!.slowDeathState).not.toBeNull();
    expect(overrideHulk!.slowDeathState!.sinkFrame).toBe(1);
    expect(overrideHulk!.slowDeathState!.midpointFrame).toBe(16);
    expect(overrideHulk!.slowDeathState!.destructionFrame).toBe(31);

    expect(logic.executeScriptAction({
      actionType: 507,
      params: [-1], // reset override
    })).toBe(true);
    expect(logic.getScriptHulkLifetimeOverrideFrames()).toBe(-1);

    expect(logic.executeScriptAction({
      actionType: 23,
      params: ['TimedHulkUnit', 'HulkTeam', { x: 24, y: 0, z: 24 }, 0],
    })).toBe(true);
    const defaultHulk = privateApi.spawnedEntities.get(2);
    expect(defaultHulk).toBeDefined();
    expect(defaultHulk!.lifetimeDieFrame).toBe(150);

    privateApi.applyWeaponDamageAmount(null, defaultHulk, 999, 'UNRESISTABLE');
    expect(defaultHulk!.slowDeathState).not.toBeNull();
    expect(defaultHulk!.slowDeathState!.sinkFrame).toBe(9);
    expect(defaultHulk!.slowDeathState!.destructionFrame).toBe(18);
    expect(defaultHulk!.slowDeathState!.midpointFrame).toBeGreaterThanOrEqual(6);
    expect(defaultHulk!.slowDeathState!.midpointFrame).toBeLessThanOrEqual(11);

    // Source parity: map load clears script bridge values.
    logic.loadMapObjects(
      makeMap([], 64, 64),
      makeRegistry(bundle),
      makeHeightmap(64, 64),
    );
    expect(logic.getScriptVisualSpeedMultiplier()).toBe(1);
    expect(logic.getScriptHulkLifetimeOverrideFrames()).toBe(-1);
  });

  it('executes unit-spawn-named-location-orientation action using source action id', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('SpawnTemplate', 'America', ['INFANTRY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      makeMap([], 64, 64),
      makeRegistry(bundle),
      makeHeightmap(64, 64),
    );

    const privateApi = logic as unknown as {
      spawnedEntities: Map<number, {
        x: number;
        z: number;
        rotationY: number;
        scriptName: string;
      }>;
      scriptNamedEntitiesByName: Map<string, number>;
      scriptTeamsByName: Map<string, {
        created: boolean;
        memberEntityIds: Set<number>;
      }>;
    };

    expect(logic.executeScriptAction({
      actionType: 514, // UNIT_SPAWN_NAMED_LOCATION_ORIENTATION
      params: ['SpawnedGuy', 'SpawnTemplate', 'SpawnTeam', { x: 40, y: 52, z: 3 }, 1.25],
    })).toBe(true);
    const entity = privateApi.spawnedEntities.get(1);
    expect(entity).toBeDefined();
    expect(entity!.x).toBeCloseTo(40);
    expect(entity!.z).toBeCloseTo(52);
    expect(entity!.rotationY).toBeCloseTo(1.25);
    expect(entity!.scriptName).toBe('SpawnedGuy');
    expect(privateApi.scriptNamedEntitiesByName.get('SpawnedGuy')).toBe(1);
    const team = privateApi.scriptTeamsByName.get('SPAWNTEAM');
    expect(team).toBeDefined();
    expect(team!.created).toBe(true);
    expect(team!.memberEntityIds.has(1)).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 309, // UNIT_SPAWN_NAMED_LOCATION_ORIENTATION (retail enum id)
      params: ['SpawnedGuyRaw', 'SpawnTemplate', 'SpawnTeam', { x: 10, y: 12, z: 0 }, 0.5],
    })).toBe(true);
    const rawEntity = privateApi.spawnedEntities.get(2);
    expect(rawEntity).toBeDefined();
    expect(rawEntity!.x).toBeCloseTo(10);
    expect(rawEntity!.z).toBeCloseTo(12);
    expect(rawEntity!.rotationY).toBeCloseTo(0.5);
    expect(rawEntity!.scriptName).toBe('SpawnedGuyRaw');
    expect(privateApi.scriptNamedEntitiesByName.get('SpawnedGuyRaw')).toBe(2);
    expect(team!.memberEntityIds.has(2)).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 514,
      params: ['SpawnedGuy2', 'MissingTemplate', 'SpawnTeam', { x: 1, y: 2, z: 0 }, 0],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 514,
      params: ['SpawnedGuy2', 'SpawnTemplate', 'SpawnTeam', 'not-a-coord', 0],
    })).toBe(false);
  });

  it('executes script set-cave-index action using source action id', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('NeutralCaveA', 'Neutral', ['STRUCTURE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 400, InitialHealth: 400 }),
          makeBlock('Behavior', 'CaveContain ModuleTag_Cave', { CaveIndex: 0 }),
        ]),
        makeObjectDef('NeutralCaveB', 'Neutral', ['STRUCTURE'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 400, InitialHealth: 400 }),
          makeBlock('Behavior', 'CaveContain ModuleTag_Cave', { CaveIndex: 1 }),
        ]),
        makeObjectDef('NeutralInfantry', 'Neutral', ['INFANTRY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      makeMap([
        makeMapObject('NeutralCaveA', 30, 30),
        makeMapObject('NeutralCaveB', 70, 30),
        makeMapObject('NeutralInfantry', 30, 30),
      ], 128, 128),
      makeRegistry(bundle),
      makeHeightmap(128, 128),
    );

    expect(logic.getCaveContainIndex(1)).toBe(0);
    expect(logic.getCaveContainIndex(2)).toBe(1);

    logic.submitCommand({ type: 'enterTransport', entityId: 3, targetTransportId: 1 });
    logic.update(1 / 30);
    expect(logic.getEntityState(3)?.statusFlags).toContain('DISABLED_HELD');

    expect(logic.executeScriptAction({
      actionType: 429, // SET_CAVE_INDEX
      params: [1, 2],
    })).toBe(false);
    expect(logic.getCaveContainIndex(1)).toBe(0);

    logic.submitCommand({ type: 'exitContainer', entityId: 3 });
    logic.update(1 / 30);
    expect(logic.getEntityState(3)?.statusFlags).not.toContain('DISABLED_HELD');

    expect(logic.executeScriptAction({
      actionType: 429,
      params: [1, 2],
    })).toBe(true);
    expect(logic.getCaveContainIndex(1)).toBe(2);

    expect(logic.executeScriptAction({
      actionType: 429,
      params: [3, 4],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 429,
      params: [999, 1],
    })).toBe(false);
  });

