    logic.submitCommand({ type: 'enterTransport', entityId: 3, targetTransportId: 1 });
    for (let i = 0; i < 5; i += 1) {
      logic.update(1 / 30);
    }

    const container = privateApi.spawnedEntities.get(1)!;
