  it('records waypoint-path completion from follow-waypoints actions', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('Ranger', 'America', ['INFANTRY'], [
          makeBlock('LocomotorSet', 'SET_NORMAL TestInfantryLoco', {}),
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
      locomotors: [
        makeLocomotorDef('TestInfantryLoco', 60),
      ],
    });

    const map = makeMap([
      makeMapObject('Ranger', 18, 20), // id 1
    ], 128, 128);
    map.waypoints = {
      nodes: [
        { id: 31, name: 'Route_A', position: { x: 20, y: 20, z: 0 }, pathLabel1: 'RouteAlpha', biDirectional: false },
        { id: 32, name: 'Route_B', position: { x: 40, y: 20, z: 0 }, pathLabel1: 'RouteAlpha', biDirectional: false },
        {
          id: 33,
          name: 'Route_C',
          position: { x: 60, y: 20, z: 0 },
          pathLabel1: 'RouteAlpha',
          pathLabel2: 'RouteOmega',
          biDirectional: false,
        },
      ],
      links: [
        { waypoint1: 31, waypoint2: 32 },
        { waypoint1: 32, waypoint2: 33 },
      ],
    };

    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      map,
      makeRegistry(bundle),
      makeHeightmap(128, 128),
    );

    expect(logic.executeScriptAction({
      actionType: 56, // NAMED_FOLLOW_WAYPOINTS (raw id)
      params: [1, 'RouteAlpha'],
    })).toBe(true);

    let completionObserved = false;
    for (let frame = 0; frame < 120; frame += 1) {
      logic.update(1 / 30);
      if (logic.evaluateScriptNamedReachedWaypointsEnd({
        entityId: 1,
        waypointPathName: 'RouteAlpha',
      })) {
        completionObserved = true;
        break;
      }
    }

    expect(completionObserved).toBe(true);
    // Source parity: completed waypoint is visible for the rest of the frame.
    expect(logic.evaluateScriptNamedReachedWaypointsEnd({
      entityId: 1,
      waypointPathName: 'RouteAlpha',
    })).toBe(true);
    expect(logic.evaluateScriptNamedReachedWaypointsEnd({
      entityId: 1,
      waypointPathName: 'RouteOmega',
    })).toBe(true);
    // Source parity: AIUpdate resets completed-waypoint at the next update.
    logic.update(1 / 30);
    expect(logic.evaluateScriptNamedReachedWaypointsEnd({
      entityId: 1,
      waypointPathName: 'RouteAlpha',
    })).toBe(false);
    expect(logic.evaluateScriptNamedReachedWaypointsEnd({
      entityId: 1,
      waypointPathName: 'RouteOmega',
    })).toBe(false);
  });

