    expect(logic.executeScriptAction({
      actionType: 464,
      params: ['America', 'WaitProto', 'Command_ScriptNoTarget'],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 465,
      params: ['America', 'WaitProto', 'Command_ScriptNoTarget'],
    })).toBe(false);

