  it('executes script freeze-time and weather actions using source action ids', () => {
    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      makeMap([], 128, 128),
      makeRegistry(makeBundle({ objects: [] })),
      makeHeightmap(128, 128),
    );

    expect(logic.isScriptTimeFrozenByScript()).toBe(false);
    expect(logic.isScriptWeatherVisible()).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 137, // FREEZE_TIME (raw id)
    })).toBe(true);
    expect(logic.isScriptTimeFrozenByScript()).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 342, // FREEZE_TIME (offset/collision id when no params)
      params: [],
    })).toBe(true);
    expect(logic.isScriptTimeFrozenByScript()).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 138, // UNFREEZE_TIME (raw id)
    })).toBe(true);
    expect(logic.isScriptTimeFrozenByScript()).toBe(false);

    expect(logic.executeScriptAction({
      actionType: 343, // UNFREEZE_TIME (offset id)
    })).toBe(true);
    expect(logic.isScriptTimeFrozenByScript()).toBe(false);

    expect(logic.executeScriptAction({
      actionType: 342, // SHOW_WEATHER (raw id when params are present)
      params: [0],
    })).toBe(true);
    expect(logic.isScriptWeatherVisible()).toBe(false);
    expect(logic.isScriptTimeFrozenByScript()).toBe(false);

    expect(logic.executeScriptAction({
      actionType: 342,
      params: [1],
    })).toBe(true);
    expect(logic.isScriptWeatherVisible()).toBe(true);
  });

  it('freezes simulation updates while camera runtime reports frozen time', () => {
    let cameraTimeFrozen = true;
    const logic = new GameLogicSubsystem(new THREE.Scene(), {
      isCameraTimeFrozen: () => cameraTimeFrozen,
    });
    logic.loadMapObjects(
      makeMap([makeMapObject('FrozenMover', 10, 10)], 128, 128),
      makeRegistry(makeBundle({
        objects: [
          makeObjectDef('FrozenMover', 'America', ['VEHICLE'], [
            makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
            makeBlock('LocomotorSet', 'SET_NORMAL LocomotorFast', {}),
          ]),
        ],
        locomotors: [
          makeLocomotorDef('LocomotorFast', 60),
        ],
      })),
      makeHeightmap(128, 128),
    );

    logic.submitCommand({ type: 'moveTo', entityId: 1, targetX: 70, targetZ: 10 });

    for (let frame = 0; frame < 10; frame += 1) {
      logic.update(1 / 30);
    }
    expect(logic.getEntityState(1)?.x).toBeCloseTo(10, 5);

    cameraTimeFrozen = false;
    for (let frame = 0; frame < 10; frame += 1) {
      logic.update(1 / 30);
    }
    expect(logic.getEntityState(1)?.x ?? 0).toBeGreaterThan(10.5);
  });

  it('scales movement updates by camera and script visual speed multipliers', () => {
    const runMovementSample = (cameraMultiplier: number, scriptMultiplier: number): number => {
      const logic = new GameLogicSubsystem(new THREE.Scene(), {
        getCameraTimeMultiplier: () => cameraMultiplier,
      });
      logic.loadMapObjects(
        makeMap([makeMapObject('SpeedScaledMover', 10, 10)], 128, 128),
        makeRegistry(makeBundle({
          objects: [
            makeObjectDef('SpeedScaledMover', 'America', ['VEHICLE'], [
              makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
              makeBlock('LocomotorSet', 'SET_NORMAL LocomotorFast', {}),
            ]),
          ],
          locomotors: [
            makeLocomotorDef('LocomotorFast', 60),
          ],
        })),
        makeHeightmap(128, 128),
      );

      expect(logic.executeScriptAction({
        actionType: 22, // SET_VISUAL_SPEED_MULTIPLIER
        params: [scriptMultiplier],
      })).toBe(true);
      logic.submitCommand({ type: 'moveTo', entityId: 1, targetX: 70, targetZ: 10 });
      for (let frame = 0; frame < 12; frame += 1) {
        logic.update(1 / 30);
      }
      return logic.getEntityState(1)?.x ?? 0;
    };

    const baselineX = runMovementSample(1, 1);
    const cameraScaledX = runMovementSample(2, 1);
    const scriptScaledX = runMovementSample(1, 2);

    expect(cameraScaledX).toBeGreaterThan(baselineX + 0.5);
    expect(scriptScaledX).toBeGreaterThan(baselineX + 0.5);
  });

