  it('executes script damage/delete/kill actions using source action ids', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('AmericaInfantry', 'America', ['INFANTRY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
        makeObjectDef('ChinaInfantry', 'China', ['INFANTRY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      makeMap([
        makeMapObject('AmericaInfantry', 10, 10), // id 1 named damage
        makeMapObject('AmericaInfantry', 12, 10), // id 2 named delete
        makeMapObject('AmericaInfantry', 14, 10), // id 3 team delete
        makeMapObject('AmericaInfantry', 16, 10), // id 4 team delete
        makeMapObject('AmericaInfantry', 18, 10), // id 5 named kill
        makeMapObject('AmericaInfantry', 20, 10), // id 6 team kill
        makeMapObject('AmericaInfantry', 22, 10), // id 7 team kill
        makeMapObject('AmericaInfantry', 24, 10), // id 8 player kill
        makeMapObject('ChinaInfantry', 26, 10), // id 9 survivor
        makeMapObject('AmericaInfantry', 28, 10), // id 10 prototype delete A
        makeMapObject('AmericaInfantry', 30, 10), // id 11 prototype delete B
        makeMapObject('AmericaInfantry', 32, 10), // id 12 prototype kill A
        makeMapObject('AmericaInfantry', 34, 10), // id 13 prototype kill B
      ], 128, 128),
      makeRegistry(bundle),
      makeHeightmap(128, 128),
    );
    expect(logic.setScriptTeamMembers('DeleteTeam', [3, 4])).toBe(true);
    expect(logic.setScriptTeamMembers('DeleteInstanceA', [10])).toBe(true);
    expect(logic.setScriptTeamPrototype('DeleteInstanceA', 'DeleteProto')).toBe(true);
    expect(logic.setScriptTeamMembers('DeleteInstanceB', [11])).toBe(true);
    expect(logic.setScriptTeamPrototype('DeleteInstanceB', 'DeleteProto')).toBe(true);
    expect(logic.setScriptTeamMembers('KillTeam', [6, 7])).toBe(true);
    expect(logic.setScriptTeamMembers('KillInstanceA', [12])).toBe(true);
    expect(logic.setScriptTeamPrototype('KillInstanceA', 'KillProto')).toBe(true);
    expect(logic.setScriptTeamMembers('KillInstanceB', [13])).toBe(true);
    expect(logic.setScriptTeamPrototype('KillInstanceB', 'KillProto')).toBe(true);

    const privateApi = logic as unknown as {
      spawnedEntities: Map<number, {
        destroyed: boolean;
      }>;
    };

    expect(logic.executeScriptAction({
      actionType: 70, // NAMED_DAMAGE
      params: [1, 999],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(1)?.destroyed).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 71, // NAMED_DELETE
      params: [2],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(2)?.destroyed).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 72, // TEAM_DELETE
      params: ['DeleteTeam'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(3)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(4)?.destroyed).toBe(true);
    expect(logic.executeScriptAction({
      actionType: 72,
      params: ['DeleteProto'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(10)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(11)?.destroyed).toBe(false);
    expect(logic.setScriptConditionTeamContext('DeleteInstanceB')).toBe(true);
    expect(logic.executeScriptAction({
      actionType: 72,
      params: ['DeleteProto'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(10)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(11)?.destroyed).toBe(true);
    logic.clearScriptConditionTeamContext();

    expect(logic.executeScriptAction({
      actionType: 73, // NAMED_KILL
      params: [5],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(5)?.destroyed).toBe(true);

    expect(logic.executeScriptAction({
      actionType: 74, // TEAM_KILL
      params: ['KillTeam'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(6)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(7)?.destroyed).toBe(true);
    expect(logic.executeScriptAction({
      actionType: 74,
      params: ['KillProto'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(12)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(13)?.destroyed).toBe(false);
    expect(logic.setScriptConditionTeamContext('KillInstanceB')).toBe(true);
    expect(logic.executeScriptAction({
      actionType: 74,
      params: ['KillProto'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(12)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(13)?.destroyed).toBe(true);
    logic.clearScriptConditionTeamContext();

    expect(logic.executeScriptAction({
      actionType: 75, // PLAYER_KILL
      params: ['America'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(8)?.destroyed).toBe(true);
    expect(privateApi.spawnedEntities.get(9)?.destroyed).toBe(false);

    expect(logic.executeScriptAction({
      actionType: 70,
      params: [999, 100],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 71,
      params: [999],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 72,
      params: ['MissingTeam'],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 73,
      params: [999],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 74,
      params: ['MissingTeam'],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 75,
      params: ['MissingSide'],
    })).toBe(false);
  });

  it('executes script ownership-transfer actions using source action ids', () => {
    const bundle = makeBundle({
      objects: [
        makeObjectDef('AmericaInfantry', 'America', ['INFANTRY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
        makeObjectDef('AmericaBeacon', 'America', ['BEACON'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 1, InitialHealth: 1 }),
        ]),
        makeObjectDef('ChinaInfantry', 'China', ['INFANTRY'], [
          makeBlock('Body', 'ActiveBody ModuleTag_Body', { MaxHealth: 100, InitialHealth: 100 }),
        ]),
      ],
    });

    const logic = new GameLogicSubsystem(new THREE.Scene());
    logic.loadMapObjects(
      makeMap([
        makeMapObject('AmericaInfantry', 10, 10), // id 1 transfer candidate
        makeMapObject('AmericaBeacon', 12, 10), // id 2 excluded from player transfer
        makeMapObject('ChinaInfantry', 14, 10), // id 3 destination-side baseline
      ], 128, 128),
      makeRegistry(bundle),
      makeHeightmap(128, 128),
    );
    logic.setSideCredits('America', 500);
    logic.setSideCredits('China', 200);

    const privateApi = logic as unknown as {
      spawnedEntities: Map<number, {
        side: string;
      }>;
    };

    expect(logic.executeScriptAction({
      actionType: 84, // PLAYER_TRANSFER_OWNERSHIP_PLAYER
      params: ['America', 'China'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(1)?.side).toBe('china');
    expect(privateApi.spawnedEntities.get(2)?.side).toBe('America');
    expect(privateApi.spawnedEntities.get(3)?.side).toBe('China');
    expect(logic.getSideCredits('America')).toBe(0);
    expect(logic.getSideCredits('China')).toBe(700);

    expect(logic.executeScriptAction({
      actionType: 85, // NAMED_TRANSFER_OWNERSHIP_PLAYER
      params: [2, 'China'],
    })).toBe(true);
    expect(privateApi.spawnedEntities.get(2)?.side).toBe('china');

    expect(logic.executeScriptAction({
      actionType: 84,
      params: ['MissingSide', 'China'],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 84,
      params: ['China', 'MissingSide'],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 85,
      params: [999, 'China'],
    })).toBe(false);
    expect(logic.executeScriptAction({
      actionType: 85,
      params: [1, 'MissingSide'],
    })).toBe(false);
  });

