    expect(logic.evaluateScriptBuildingEntered({
      side: 'China',
      entityId: 1,
    })).toBe(false);
    expect(logic.evaluateScriptIsBuildingEmpty({
      entityId: 1,
    })).toBe(false);

    // Source parity: OpenContain::update clears player-entered flag each frame.
